17582: const char *
17583: ix86_output_call_insn (rtx_insn *insn, rtx call_op)
17584: {
17585:   bool direct_p = constant_call_address_operand (call_op, VOIDmode);
17586:   bool output_indirect_p
17587:     = (!TARGET_SEH
17588:        && cfun->machine->indirect_branch_type != indirect_branch_keep);
