17591: 
17592:   if (SIBLING_CALL_P (insn))
17593:     {
17594:       output_return_instrumentation ();
17595:       if (direct_p)
17596: 	{
17597: 	  if (ix86_nopic_noplt_attribute_p (call_op))
17598: 	    {
17599: 	      direct_p = false;
17600: 	      if (TARGET_64BIT)
17601: 		{
17602: 		  if (output_indirect_p)
17603: 		    xasm = "{%p0@GOTPCREL(%%rip)|[QWORD PTR %p0@GOTPCREL[rip]]}";
17604: 		  else
17605: 		    xasm = "%!jmp\t{*%p0@GOTPCREL(%%rip)|[QWORD PTR %p0@GOTPCREL[rip]]}";
17606: 		}
17607: 	      else
17608: 		{
17609: 		  if (output_indirect_p)
17610: 		    xasm = "{%p0@GOT|[DWORD PTR %p0@GOT]}";
17611: 		  else
17612: 		    xasm = "%!jmp\t{*%p0@GOT|[DWORD PTR %p0@GOT]}";
17613: 		}
17614: 	    }
17615: 	  else
17616: 	    xasm = "%!jmp\t%P0";
17617: 	}
17618:       /* SEH epilogue detection requires the indirect branch case
17619: 	 to include REX.W.  */
