17621: 	xasm = "%!rex.W jmp\t%A0";
17622:       else
17623: 	{
17624: 	  if (output_indirect_p)
17625: 	    xasm = "%0";
17626: 	  else
17627: 	    xasm = "%!jmp\t%A0";
17628: 	}
17629: 
17630:       if (output_indirect_p && !direct_p)
17631: 	ix86_output_indirect_branch (call_op, xasm, true);
